import { VectorStoreIndex, Document } from 'llamaindex';
import { OpenAI } from '@llamaindex/llms/openai';

const documents = [
  new Document({
    text: 'Refund policy: 30 days from delivery date',
    metadata: { category: 'billing' }
  })
];

const llm = new OpenAI({ model: 'gpt-4' });
const index = await VectorStoreIndex.fromDocuments(documents, {
  llm,
  embedModel: 'text-embedding-ada-002'
});

const queryEngine = index.asQueryEngine();

import { FunctionTool } from 'llamaindex';

const orderLookup = async (orderId: string): Promise<string> => {
  // Mock CRM call
  return `Order ${orderId}: shipped, refund eligible`;
};

const createTicket = async (email: string, issue: string): Promise<string> => {
  return `Ticket #123 created for ${email}: ${issue}`;
};

const orderTool = new FunctionTool({
  name: 'order_lookup',
  description: 'Lookup order status',
  fn: orderLookup
});

const ticketTool = new FunctionTool({
  name: 'create_ticket',
  description: 'Create support ticket',
  fn: createTicket
});

queryEngine = index.asQueryEngine({
  tools: [orderTool, ticketTool]
});

