import { verify } from 'vex-sdk';

const safeQuery = async (query: string): Promise<string> => {
  const response = await queryEngine.query({ query });

  const verified = await verify({
    input: query,
    output: response.toString(),
    checks: [
      'response_accuracy',
      'pii_filtering',
      'tone_consistency:professional',
      'policy_compliance',
      'escalation_triggers'
    ]
  });

  if (verified === 'BLOCK') {
    throw new Error('Response blocked - escalating');
  }

  return verified;
};

// Usage
const result = await safeQuery('Refund order #12345?');
